import React, { useState, useEffect } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import axios from 'axios';
import logo from '../assets/Logo.png';

const Header = () => {
    const [categories, setCategories] = useState([]);
    const [searchTerm, setSearchTerm] = useState('');
    const navigate = useNavigate();

    useEffect(() => {
        axios.get('http://localhost:5000/api/categories')
            .then(res => setCategories(res.data))
            .catch(err => console.error(err));
    }, []);

    const handleSearch = (e) => {
        e.preventDefault();
        if (searchTerm.trim()) {
   
            navigate(`/search?q=${searchTerm}`);
        }
    };

    return (
        <header className="bg-white border-bottom sticky-top">
            <div className="container py-3">
                <div className="row align-items-center">
                
                    <div className="col-12 col-lg-4 d-flex justify-content-between align-items-center">
                        <Link to="/">
                            <img src={logo} alt="Logo Région" style={{ height: '70px' }} />
                        </Link>
                    
                        <button className="navbar-toggler d-lg-none" type="button" data-bs-toggle="collapse" data-bs-target="#navContent">
                            <span className="navbar-toggler-icon"></span>
                        </button>
                    </div>

                    <div className="col-12 col-lg-8 mt-3 mt-lg-0">
                        <div className="d-flex flex-column align-items-end">

                            <form onSubmit={handleSearch} className="position-relative mb-2" style={{ width: '300px' }}>
                                <input
                                    className="form-control border-0 border-bottom rounded-0 shadow-none ps-0"
                                    type="search"
                                    placeholder="Rechercher"
                                    style={{ borderBottomColor: '#007bff !important' }}
                                    onChange={(e) => setSearchTerm(e.target.value)}
                                />
                                <button type="submit" className="btn position-absolute end-0 top-0 text-primary">
                                    <i className="bi bi-search">🔍</i>
                                </button>
                            </form>

                            <nav className="collapse d-lg-block" id="navContent">
                                <ul className="nav justify-content-end">
                                    {categories.map(cat => (
                                        <li className="nav-item" key={cat.id}>
                                            <Link className="nav-link text-dark fw-normal px-3" to={`/category/${cat.id}`}>
                                                {cat.name}
                                            </Link>
                                        </li>
                                    ))}
                                </ul>
                            </nav>
                        </div>
                    </div>
                </div>
            </div>
        </header>
    );
};

export default Header;
